<?php
namespace Database\Seeders;
use App\Models\{BankAccount,Business,Customer,Expense,Product,User,Vendor}; use Illuminate\Database\Seeder; use Illuminate\Support\Facades\Hash;
class DatabaseSeeder extends Seeder { public function run(): void { $user=User::firstOrCreate(['email'=>'admin@nairahq.test'], ['name'=>'NairaHQ Admin','password'=>Hash::make('Password@12345'),'is_platform_admin'=>true]); $business=Business::firstOrCreate(['name'=>'NairaHQ Demo'], ['owner_id'=>$user->id,'email'=>'hello@nairahq.com','currency'=>'NGN','vat_rate'=>7.5,'country'=>'Nigeria']); $user->businesses()->syncWithoutDetaching([$business->id=>['role'=>'owner']]); $user->forceFill(['current_business_id'=>$business->id])->save(); Customer::firstOrCreate(['business_id'=>$business->id,'email'=>'customer@example.com'], ['name'=>'Sample Customer','phone'=>'08000000000']); Vendor::firstOrCreate(['business_id'=>$business->id,'email'=>'vendor@example.com'], ['name'=>'Sample Vendor']); Product::firstOrCreate(['business_id'=>$business->id,'name'=>'Consulting Service'], ['type'=>'service','unit_price'=>50000,'taxable'=>true,'active'=>true]); BankAccount::firstOrCreate(['business_id'=>$business->id,'name'=>'Main Account'], ['bank_name'=>'Demo Bank','currency'=>'NGN','opening_balance'=>0,'current_balance'=>0]); Expense::firstOrCreate(['business_id'=>$business->id,'description'=>'Internet subscription'], ['expense_date'=>now(),'category'=>'Utilities','amount'=>25000,'tax_amount'=>0,'status'=>'paid']); } }
